  ('heelevel3-9e7ddffc-moex-00006', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-114-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '咚咚開了一家冷飲店，一杯珍珠奶茶賣50元，食材成本為20元，僱用人力成本14元，設備的利 息與折舊為2元。另外，咚咚自己的人力投入設算薪資6元，使用自有房屋為店面設算房租5元。 則咚咚銷售一杯珍珠奶茶的經濟利潤為何？', '["3元", "6元", "11元", "14元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "c23316d7f2cb", "answer_pdf_sha1": "92e118424728", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
