  ('heelevel3-9e7ddffc-moex-00009', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-114-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '某一獨占廠商面對的市場需求曲線為一直線，邊際成本固定在20，極大化利潤的產量與價格分別 為10與30，消費者剩餘為何？', '["25", "50", "75", "100"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "c23316d7f2cb", "answer_pdf_sha1": "92e118424728", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
