  ('heelevel3-9e7ddffc-moex-00012', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-114-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '關於一般均衡（generalequilibrium）的敘述，下列何者錯誤？', '["一般均衡指的是當一商品或勞務的供給等於其需求時的狀態", "達到一般均衡時，只有相對價格會被決定", "一般均衡指的是每一個體都在能夠支付得起的商品組合中，選擇其最喜歡的組合", "一般均衡指的是，若共有8個市場，其中5個的超額需求等於零，剩下3個市場的超額需求必 等於零"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "c23316d7f2cb", "answer_pdf_sha1": "92e118424728", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
  ('heelevel3-9e7ddffc-moex-00013', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-114-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '假設汽油的需求函數為Q=33－P，廠商生產汽油的邊際成本函數為MC=0.5Q，其中Q為汽油產 量。假設生產一單位汽油所排放的廢氣對社會的損害為3，且無外部效益，下列敘述何者錯誤？', '["市場自由運作的無謂損失（deadweightloss）為3", "政府應課汽油稅，每單位稅額等於3", "若政府課徵滿足社會福利最大的稅額，消費者需負擔每單位的稅額為2", "社會福利最大時每單位汽油價格為14"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "c23316d7f2cb", "answer_pdf_sha1": "92e118424728", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
